-- Karari Beauty seed data
-- Generated by scripts/generate-supabase-seed.mjs from data/categories.js and data/products.js.
begin;

on conflict (slug) do update set
  name = excluded.name,
  description = excluded.description,
  product_count_label = excluded.product_count_label,
  image_url = excluded.image_url,
  featured = excluded.featured,
  sort_order = excluded.sort_order,
  is_active = excluded.is_active;

on conflict (slug) do update set
  category_id = excluded.category_id,
  name = excluded.name,
  sku = excluded.sku,
  description = excluded.description,
  short_description = excluded.short_description,
  price = excluded.price,
  original_price = excluded.original_price,
  discount_label = excluded.discount_label,
  rating = excluded.rating,
  badge = excluded.badge,
  offer = excluded.offer,
  image_url = excluded.image_url,
  category_name = excluded.category_name,
  category_slug = excluded.category_slug,
  tags = excluded.tags,
  is_featured = excluded.is_featured,
  is_active = excluded.is_active,
  stock_status = excluded.stock_status,
  sort_order = excluded.sort_order;

delete from public.product_images where product_id in (select id from public.products where sku like 'KB-%');


on conflict (slug) do update set
  name = excluded.name,
  theme = excluded.theme,
  is_active = excluded.is_active,
  start_date = excluded.start_date,
  end_date = excluded.end_date,
  hero_title = excluded.hero_title,
  hero_subtitle = excluded.hero_subtitle,
  offer_label = excluded.offer_label,
  featured_category_slugs = excluded.featured_category_slugs,
  config = excluded.config;

commit;
